// Numerically stable max reduction with identity validation
template<typename T>
__device__ float stable_max_reduction(const T* input, int dim_size, int tid, int blockDim_x) {
    // Initialize with proper identity element for max
    const float MAX_IDENTITY = -std::numeric_limits<float>::infinity();
    float thread_max = MAX_IDENTITY;

    // First pass: find any finite value
    bool has_finite = false;
    for (int i = tid; i < dim_size; i += blockDim_x) {
        float val = to_float<T>(input[i]);
        if (isfinite(val)) {
            thread_max = fmaxf(thread_max, val);
            has_finite = true;
        }
    }

    __shared__ float sdata_max[1024];
    __shared__ bool sdata_has_finite[1024];

    sdata_max[tid] = thread_max;
    sdata_has_finite[tid] = has_finite;
    __syncthreads();

    // Reduction for max
    for (int s = blockDim_x / 2; s > 0; s >>= 1) {
        if (tid < s) {
            sdata_max[tid] = fmaxf(sdata_max[tid], sdata_max[tid + s]);
            sdata_has_finite[tid] = sdata_has_finite[tid] || sdata_has_finite[tid + s];
        }
        __syncthreads();
    }

    // If no finite values found, return -inf
    if (!sdata_has_finite[0]) {
        return -std::numeric_limits<float>::infinity();
    }

    return sdata_max[0];
}

// Numerically stable sum reduction with overflow protection
template<typename T>
__device__ float stable_sum_reduction(const T* input, float global_max, 
                                      int dim_size, int tid, int blockDim_x) {
    float thread_sum = 0.0f;

    // If max is -inf, all values are -inf
    if (!isfinite(global_max) && global_max < 0) {
        return 0.0f;
    }

    // Compute sum with overflow protection
    for (int i = tid; i < dim_size; i += blockDim_x) {
        float val = to_float<T>(input[i]);
        if (isfinite(val)) {
            float exp_val = expf(val - global_max);
            // Prevent NaN from overflow
            if (isfinite(exp_val)) {
                thread_sum += exp_val;
            }
        }
    }

    __shared__ float sdata_sum[1024];
    sdata_sum[tid] = thread_sum;
    __syncthreads();

    // Reduction for sum
    for (int s = blockDim_x / 2; s > 0; s >>= 1) {
        if (tid < s) {
            sdata_sum[tid] += sdata_sum[tid + s];
        }
        __syncthreads();
    }

    return sdata_sum[0];
}

template<typename T>
__global__ void log_softmax_kernel(
    const T* __restrict__ input,
    T* __restrict__ output,
    const int batch_size,
    const int dim_size
) {
    // Each block handles one batch element
    const int batch_idx = blockIdx.x;
    const int tid = threadIdx.x;

    const T* batch_input = input + batch_idx * dim_size;
    T* batch_output = output + batch_idx * dim_size;

    // Step 1: Find max using stable reduction
    float global_max = stable_max_reduction<T>(batch_input, dim_size, tid, blockDim.x);
    __syncthreads();

    // Step 2: Compute sum(exp(x - max)) with stable reduction
    float total_sum = stable_sum_reduction<T>(batch_input, global_max, dim_size, tid, blockDim.x);
    __syncthreads();

    // Step 3: Compute final log_softmax values with overflow protection
    float log_sum_exp;
    if (total_sum > 0.0f) {
        log_sum_exp = logf(total_sum) + global_max;
    } else {
        // Handle case where all inputs are -inf
        log_sum_exp = -std::numeric_limits<float>::infinity();
    }

    // Compute output values
    for (int i = tid; i < dim_size; i += blockDim.x) {
        float val = to_float<T>(batch_input[i]);
        float result;

        if (!isfinite(val) || !isfinite(log_sum_exp)) {
            // Handle special cases
            if (!isfinite(val) && val < 0 && !isfinite(log_sum_exp) && log_sum_exp < 0) {
                result = -std::numeric_limits<float>::infinity();
            } else if (!isfinite(val) && val > 0) {
                result = val - log_sum_exp;  // +inf case
            } else {
                result = val - log_sum_exp;
            }
        } else {
            result = val - log_sum_exp;
        }

        // Clamp to reasonable range to prevent overflow in conversion
        const float MAX_OUTPUT = 50.0f;  // exp(50) ~ 5e21, safe for float32
        const float MIN_OUTPUT = -100.0f; // exp(-100) ~ 3.7e-44, near underflow
        result = fminf(fmaxf(result, MIN_OUTPUT), MAX_OUTPUT);

        batch_output[i] = from_float<T>(result);
    }
}

torch::Tensor log_softmax_cuda(torch::Tensor input, int dim) {
    auto input_contiguous = input.contiguous();
    auto output = torch::empty_like(input_contiguous);

    // Only support 2D tensors with dim=1 for now
    TORCH_CHECK(input_contiguous.dim() == 2, "Input must be 2D tensor");
    TORCH_CHECK(dim == 1, "Only dim=1 is supported");

    // Validate input doesn't contain extreme values that would cause overflow
